import React, { useState, useEffect, useCallback } from "react";
import axios from "axios";
import { ResponsiveContainer, AreaChart, Area, YAxis } from "recharts";
import {
  Bitcoin,
  Coins,
  CircleDot,
  Database,
  Smartphone,
  XCircle,
} from "lucide-react";
import "../../styles/financecoin.css";

const API = "https://corsproxy.io/?https://api.btcturk.com";

const COIN_CONFIGS = {
  BTCTRY: { name: "BITCOIN", symbol: "BTC", icon: Bitcoin, color: "#F7931A" },
  ETHTRY: { name: "ETHEREUM", symbol: "ETH", icon: Coins, color: "#627EEA" },
  SOLTRY: { name: "SOLANA", symbol: "SOL", icon: Smartphone, color: "#14F195" },
  BNBTRY: {
    name: "BINANCE COIN",
    symbol: "BNB",
    icon: CircleDot,
    color: "#F3BA2F",
  },
  ADATRY: { name: "CARDANO", symbol: "ADA", icon: Database, color: "#0033AD" },
  XRPTRY: { name: "XRP", symbol: "XRP", icon: XCircle, color: "#FFFFFF" },
};

const CryptoBox = ({ coinData }) => {
  const config = COIN_CONFIGS[coinData.pair];
  const Icon = config.icon;
  const isPositive = coinData.dailyPercent >= 0;

  return (
    <div className="crypto-item-box">
      <div className="coin-left-section">
        <div
          className="coin-icon-wrapper"
          style={{
            background: `linear-gradient(135deg, ${config.color}33, ${config.color}11)`,
          }}
        >
          <Icon color={config.color} size={28} />
        </div>

        <div className="coin-details">
          <h3 className="coin-title">
            {config.name} ({config.symbol})
          </h3>

          <div className="price-info">
            <span className="coin-price">
              {parseFloat(coinData.last).toLocaleString("tr-TR")} ₺
            </span>

            <span className={`coin-change ${isPositive ? "up" : "down"}`}>
              {isPositive ? "+" : ""}
              {coinData.dailyPercent.toFixed(2)}%
            </span>
          </div>
        </div>
      </div>

      <div className="coin-right-section">
        <ResponsiveContainer width="100%" height={60}>
          <AreaChart data={coinData.history}>
            <defs>
              <linearGradient
                id={`color-${config.symbol}`}
                x1="0"
                y1="0"
                x2="0"
                y2="1"
              >
                <stop offset="5%" stopColor={config.color} stopOpacity={0.3} />
                <stop offset="95%" stopColor={config.color} stopOpacity={0} />
              </linearGradient>
            </defs>

            <YAxis hide domain={["dataMin", "dataMax"]} />

            <Area
              type="monotone"
              dataKey="close"
              stroke={config.color}
              fill={`url(#color-${config.symbol})`}
              strokeWidth={2}
              dot={false}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default function FinanceCoin() {
  const [marketData, setMarketData] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchFullData = useCallback(async () => {
    try {
      // ticker
      const tickerRes = await axios.get(`${API}/api/v2/ticker`);

      const filteredPairs = tickerRes.data.data.filter(
        (c) => COIN_CONFIGS[c.pair]
      );

      const fullData = await Promise.all(
        filteredPairs.map(async (coin) => {
          try {
            const ohlcRes = await axios.get(
              `${API}/api/v2/graph/history/v1/klines?symbol=${coin.pair}&resolution=60&limit=24`
            );

            const history = ohlcRes.data.data.map((item) => ({
              close: item.c,
            }));

            return { ...coin, history };
          } catch {
            return { ...coin, history: [] };
          }
        })
      );

      setMarketData(fullData);
      setLoading(false);
    } catch (err) {
      console.error("API Hatası:", err);
    }
  }, []);

  useEffect(() => {
    fetchFullData();
    const interval = setInterval(fetchFullData, 30000);

    return () => clearInterval(interval);
  }, [fetchFullData]);

  if (loading) return <div className="loader">Veriler Yükleniyor...</div>;

  return (
    <div className="market-insight-wrapper">
      <div className="market-header">
        <h2 className="market-main-title">CRYPTO MARKET INSIGHTS</h2>
        <div className="live-indicator">
          <span>●</span> CANLI
        </div>
      </div>

      <div className="crypto-boxes-container">
        {marketData.map((coin) => (
          <CryptoBox key={coin.pair} coinData={coin} />
        ))}
      </div>
    </div>
  );
}
